import { useEffect, useState } from "react";
import api from "../api";

const PAGE_SIZE = 10;
const money = v => (Number(v||0)).toLocaleString("vi-VN")+" ₫";

export default function Payments(){
    const [rows,setRows]=useState([]);
    const [page,setPage]=useState(0);
    const [totalPages,setTotalPages]=useState(1);
    const [loading,setLoading]=useState(true);

    const [contracts,setContracts]=useState([]);
    const [showModal,setShowModal]=useState(false);
    const [editing,setEditing]=useState(null);
    const [form,setForm]=useState({
        contractId:"", date:"", amount:0, method:"Chuyển khoản", confirmer:"", status:"Chờ xác nhận"
    });

    function normalizeList(d){ return Array.isArray(d)?{list:d,pages:1}:{list:d?.content||[],pages:d?.totalPages||1}; }

    useEffect(()=>{ (async()=>{
        try{
            const {data}=await api.get("/api/contracts",{params:{page:0,size:1000}});
            const content = Array.isArray(data)?data:(data?.content||[]);
            setContracts(content);
            if(content[0]?.id) setForm(f=>({...f,contractId: content[0].id}));
        }catch{}
    })(); },[]);

    useEffect(()=>{ load(); },[page]);

    async function load(){
        setLoading(true);
        try{
            const {data}=await api.get("/api/payments",{params:{page,size:PAGE_SIZE,sort:"id,desc"}});
            const {list,pages}=normalizeList(data);
            setRows(list); setTotalPages(pages);
        }catch(e){ console.error(e); setRows([]); setTotalPages(1); }
        finally{ setLoading(false); }
    }

    function openCreate(){
        setEditing(null);
        setForm({
            contractId: contracts[0]?.id || "",
            date: new Date().toISOString().slice(0,10),
            amount: 0,
            method: "Chuyển khoản",
            confirmer: "",
            status: "Chờ xác nhận"
        });
        setShowModal(true);
    }
    function openEdit(p){
        setEditing(p);
        setForm({
            contractId: p.contractId || p.contract?.id || "",
            date: p.date || p.paymentDate || "",
            amount: p.amount ?? p.money ?? 0,
            method: p.method || p.paymentMethod || "Chuyển khoản",
            confirmer: p.confirmer || p.confirmedBy || "",
            status: p.status || p.paymentStatus || "Chờ xác nhận"
        });
        setShowModal(true);
    }

    async function save(e){
        e.preventDefault();
        const payload = {
            contractId: Number(form.contractId),
            date: form.date,
            amount: Number(form.amount),
            method: form.method,
            confirmer: form.confirmer,
            status: form.status
        };
        try{
            if(editing) await api.put(`/api/payments/${editing.id}`, payload);
            else        await api.post("/api/payments", payload);
            setShowModal(false); await load();
        }catch(err){ alert(err?.response?.data?.message || "Lưu thanh toán thất bại"); }
    }

    async function remove(row){
        if(!window.confirm("Xoá đợt thanh toán này?")) return;
        try{ await api.delete(`/api/payments/${row.id}`); await load(); }
        catch(err){ alert(err?.response?.data?.message || "Xoá thanh toán thất bại"); }
    }

    return (
        <div className="space-y-4">
            <div className="flex items-center justify-between">
                <div>
                    <h2 className="text-lg font-semibold">Thanh toán</h2>
                    <p className="text-sm text-slate-500">Quản lý các đợt thanh toán theo hợp đồng</p>
                </div>
                <button onClick={openCreate} className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">Thêm đợt thanh toán</button>
            </div>

            <div className="bg-white rounded-2xl border border-indigo-100 shadow overflow-hidden">
                <div className="overflow-auto">
                    <table className="min-w-full text-sm">
                        <thead className="bg-indigo-50 text-slate-600">
                        <tr>
                            <th className="px-4 py-3 text-left">Mã HĐ</th>
                            <th className="px-4 py-3 text-left">Ngày</th>
                            <th className="px-4 py-3 text-left">Số tiền</th>
                            <th className="px-4 py-3 text-left">Phương thức</th>
                            <th className="px-4 py-3 text-left">Trạng thái</th>
                            <th className="px-4 py-3 text-left">Xác nhận</th>
                            <th className="px-4 py-3 text-right">Thao tác</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y">
                        {loading ? (
                            <tr><td className="px-4 py-6" colSpan={7}>Đang tải…</td></tr>
                        ) : rows.length===0 ? (
                            <tr><td className="px-4 py-6" colSpan={7}>Chưa có dữ liệu</td></tr>
                        ) : rows.map(p=>{
                            const code =
                                p.contractCode ||
                                p.contract?.code ||
                                (p.contractId ? ("HD-"+p.contractId) : "");
                            return (
                                <tr key={p.id} className="hover:bg-indigo-50/40">
                                    <td className="px-4 py-3 font-medium">{code}</td>
                                    <td className="px-4 py-3">{p.date || p.paymentDate}</td>
                                    <td className="px-4 py-3">{money(p.amount ?? p.money)}</td>
                                    <td className="px-4 py-3">{p.method || p.paymentMethod}</td>
                                    <td className="px-4 py-3">
                      <span className={"px-2 py-0.5 rounded-full text-xs "+
                          ((p.status||"") === "Đã thanh toán" ? "bg-emerald-100 text-emerald-700":"bg-amber-100 text-amber-700")}>
                        {p.status || p.paymentStatus || "-"}
                      </span>
                                    </td>
                                    <td className="px-4 py-3">{p.confirmer || p.confirmedBy || "-"}</td>
                                    <td className="px-4 py-3 text-right">
                                        <div className="inline-flex gap-2">
                                            <button onClick={()=>openEdit(p)} className="px-2 py-1 rounded bg-indigo-50 text-indigo-700 hover:bg-indigo-100">Sửa</button>
                                            <button onClick={()=>remove(p)} className="px-2 py-1 rounded bg-rose-50 text-rose-700 hover:bg-rose-100">Xóa</button>
                                        </div>
                                    </td>
                                </tr>
                            );
                        })}
                        </tbody>
                    </table>
                </div>
            </div>

            <div className="flex gap-2">
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                        onClick={()=>setPage(p=>Math.max(0,p-1))} disabled={page<=0}>← Trước</button>
                <div className="px-3 py-1.5 text-sm">Trang {page+1}/{totalPages}</div>
                <button className="px-3 py-1.5 rounded bg-slate-100 disabled:opacity-50"
                        onClick={()=>setPage(p=>p+1)} disabled={page+1>=totalPages}>Sau →</button>
            </div>

            {/* Modal */}
            {showModal && (
                <div className="fixed inset-0 z-40 bg-black/40 grid place-items-center p-4">
                    <div className="w-full max-w-3xl bg-white rounded-2xl shadow-xl border border-indigo-100">
                        <div className="p-5 border-b flex items-center justify-between">
                            <div className="font-semibold">{editing?"Sửa đợt thanh toán":"Thêm đợt thanh toán"}</div>
                            <button className="text-slate-500 hover:text-slate-700" onClick={()=>setShowModal(false)}>Đóng</button>
                        </div>
                        <form onSubmit={save} className="p-5 grid grid-cols-1 md:grid-cols-2 gap-4">
                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Hợp đồng</label>
                                <select required value={form.contractId} onChange={e=>setForm(f=>({...f,contractId:e.target.value}))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    {contracts.map(ct=>{
                                        const code = ct.code || ct.contractCode || `HD-${ct.id}`;
                                        const cus  = ct.customer?.name || ct.customerName || "";
                                        return <option key={ct.id} value={ct.id}>{code} - {cus}</option>;
                                    })}
                                </select>
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Ngày</label>
                                <input required type="date" value={form.date} onChange={e=>setForm(f=>({...f,date:e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Số tiền (₫)</label>
                                <input required type="number" min="0" value={form.amount} onChange={e=>setForm(f=>({...f,amount:e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow"/>
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Phương thức</label>
                                <select value={form.method} onChange={e=>setForm(f=>({...f,method:e.target.value}))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    <option>Chuyển khoản</option>
                                    <option>Tiền mặt</option>
                                </select>
                            </div>
                            <div>
                                <label className="text-sm text-slate-600">Người xác nhận</label>
                                <input value={form.confirmer} onChange={e=>setForm(f=>({...f,confirmer:e.target.value}))}
                                       className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow" placeholder="VD: Kế toán A"/>
                            </div>
                            <div className="md:col-span-2">
                                <label className="text-sm text-slate-600">Trạng thái</label>
                                <select value={form.status} onChange={e=>setForm(f=>({...f,status:e.target.value}))}
                                        className="w-full px-3 py-2 rounded-lg border border-indigo-100 bg-white shadow">
                                    <option>Chờ xác nhận</option>
                                    <option>Đã thanh toán</option>
                                </select>
                            </div>
                            <div className="md:col-span-2 flex items-center justify-end gap-2 pt-2">
                                <button type="button" className="px-3 py-2 rounded-lg bg-slate-100 hover:bg-slate-200" onClick={()=>setShowModal(false)}>Huỷ</button>
                                <button className="px-3 py-2 rounded-lg bg-indigo-600 text-white hover:bg-indigo-700">Lưu</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}
